double sin_phase_table(double phase) {
    double fixed_phase = fmod(phase, 1);
    double quad_phase = 4 * fixed_phase; //initializes variables
    double location = fmod(quad_phase, 1);
    int i = round(location * 131072);
    int floor_of_phase = floor(quad_phase);
    double function_output;
    switch(floor_of_phase){
        case 0:
            function_output = sines[i] ; break;
        case 1:
            function_output = sines[131072 - i] ; break;
        case 2:
            function_output = - sines[i] ; break;
        case 3:
            function_output = - sines[131072 - i] ; break;
        case 4:
            function_output = 0 ; break;

    default: printf("Error; input doesn't match any case");
        }
return function_output;
}

double cos_phase_table(double phase) {
    double fixed_phase = fmod(phase, 1);
    double quad_phase = 4 * fixed_phase; //initializes variables
    double location = fmod(quad_phase, 1);
    int i = round(location * 131072);
    int floor_of_phase = floor(quad_phase);
    double function_output;
    switch(floor_of_phase){
        case 0:
            function_output = sines[131072 - i] ; break;
        case 1:
            function_output = - sines[i] ; break;
        case 2:
            function_output = - sines[131072 - i] ; break;
        case 3:
            function_output = sines[i] ; break;
        case 4:
            function_output = 1 ; break;

    default: printf("Error; input doesn't match any case");
        }
return function_output;
}



/* Author: Mathias Zechmeister
 * Date: 2018-10-01
 */
void gls(double* t,double* y,double* e_y, int n, long nk, double fstep,double* f,double* p) {


   /*
    * t : time array
    * y : data array
    * e_y : uncertainties array
    * n : length of data
        * fbeg : start frequencies
        * nk : number of frequencies
        * fstep : step size for frequency
    * f : frequency array
    */

   double wsum=0, Y=0, YY=0, C, S, YC, YS, CC, SS, CS, D, tmp;
   double *w = (double *) malloc(n * sizeof(double)),
          *wy = (double *) malloc(n * sizeof(double)),
          *cosx = (double *) malloc(n * sizeof(double)),
          *sinx = (double *) malloc(n * sizeof(double)),
          *cosdx = (double *) malloc(n * sizeof(double)),
          *sindx = (double *) malloc(n * sizeof(double));
   int i, k;

   for (i=0; i<n; i++) {
      /* weights */
      w[i] = 1 / (e_y[i] * e_y[i]);
      wsum += w[i];
   }
   for (i=0; i<n; i++) {
      /* mean */
      w[i] /= wsum;                 /* normalised weights */
      Y += w[i] * y[i];             /* Eq. (7) */
   }
   for (i=0; i<n; i++) {
      /* variance */
      wy[i] = y[i] - Y;             /* Subtract weighted mean */
      YY += w[i] * wy[i] * wy[i];   /* Eq. (10) */
      wy[i] *= w[i];                /* attach weights */

      /* Prepare trigonometric recurrences cos(dx)+i sin(dx) */
      cosdx[i] = cos_phase_table(fstep * t[i]);
      sindx[i] = sin_phase_table(fstep * t[i]);
   }
   /*printf("%i \n");*/
   for ( k=0; k<nk; k++) {

      C = S = YC = YS = CC = CS = 0;
      for (i=0; i<n; i++) {
         if (k % 1000 == 0) {
            /* init/refresh recurrences to stop error propagation */
            cosx[i] = cos_phase_table(f[k] * t[i]);
            sinx[i] = sin_phase_table(f[k] * t[i]);
         }

         C += w[i] * cosx[i];              /* Eq. (8) */
/*          printf("%.10g %.10g %.10g %.10g %.10g\n", f[k], w[i], t[i], cosx[i], C);*/
         S += w[i] * sinx[i];              /* Eq. (9) */
         YC += wy[i] * cosx[i];            /* Eq. (11) */
         YS += wy[i] * sinx[i];            /* Eq. (12) */
/*         wcosx = w * cosx; */
         CC += w[i] * cosx[i] * cosx[i];   /* Eq. (13) */
         CS += w[i] * cosx[i] * sinx[i];   /* Eq. (15) */

         /* increase freq for next loop */
         tmp = cosx[i] * cosdx[i] - sinx[i] * sindx[i];
         sinx[i] = cosx[i] * sindx[i] + sinx[i] * cosdx[i];
         cosx[i] = tmp;
      }

      SS = 1. - CC;
      CC -= C * C;              /* Eq. (13) */
      SS -= S * S;              /* Eq. (14) */
      CS -= C * S;              /* Eq. (15) */
      D = CC*SS - CS*CS;        /* Eq. (6) */

/*         self._a = (YC*SS-YS*CS) / D
//         self._b = (YS*CC-YC*CS) / D
//         self._off = -self._a*C - self._b*S
*/
      /* power */
      p[k] = (SS*YC*YC + CC*YS*YS - 2.*CS*YC*YS) / (YY*D);  /* Eq. (5) in ZK09 */
   }
}
